INSERT INTO questions (type, difficulty, question_text, option_a, option_b, option_c, option_d, correct_answer, svg_content, is_practice, is_active) VALUES
('pattern_recognition', 'easy', 'What comes next in the size progression?', 'Small', 'Medium', 'Large', 'Extra large', 'c', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="25" r="5" fill="#0084AD"/><circle cx="40" cy="25" r="10" fill="#0084AD"/><circle cx="70" cy="25" r="15" fill="#0084AD"/><circle cx="110" cy="25" r="20" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
('pattern_recognition', 'easy', 'Which shape comes next - square or circle?', 'Square', 'Circle', 'Triangle', 'Pentagon', 'a', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="25" r="8" fill="#0084AD"/><rect x="32" y="17" width="16" height="16" fill="#0084AD"/><circle cx="60" cy="25" r="8" fill="#0084AD"/><rect x="77" y="17" width="16" height="16" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
('pattern_recognition', 'easy', 'Find the pattern in this rotation.', 'Rotated 45°', 'Rotated 90°', 'Rotated 180°', 'Not rotated', 'b', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><polygon points="15,15 25,35 5,35" fill="#0084AD"/><polygon points="40,15 50,15 45,35" fill="#0084AD"/><polygon points="70,35 80,35 75,15" fill="#0084AD"/><polygon points="105,35 115,15 95,15" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
('pattern_recognition', 'easy', 'Which continues the filled pattern?', 'Unfilled', 'Half-filled', 'Fully-filled', 'Striped', 'c', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="25" r="8" fill="white" stroke="#0084AD" stroke-width="2"/><circle cx="40" cy="25" r="8" fill="#0084AD" opacity="0.5"/><circle cx="65" cy="25" r="8" fill="#0084AD"/><circle cx="95" cy="25" r="8" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
('pattern_recognition', 'easy', 'What shape replaces the question mark?', 'Triangle', 'Square', 'Circle', 'Star', 'b', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="20" cy="25" r="8" fill="#0084AD"/><circle cx="45" cy="25" r="8" fill="#0084AD"/><rect x="62" y="17" width="16" height="16" fill="#0084AD"/><rect x="87" y="17" width="16" height="16" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
