('pattern_recognition', 'easy', 'Which direction does the arrow point next?', 'Up', 'Down', 'Left', 'Right', 'a', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><polygon points="15,35 15,15 5,25" fill="#0084AD"/><polygon points="40,5 40,45 50,25" fill="#0084AD"/><polygon points="70,35 70,15 80,25" fill="#0084AD"/><polygon points="95,5 95,45 85,25" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
('pattern_recognition', 'easy', 'Count the sides - what comes next?', '5 sides', '6 sides', '7 sides', '8 sides', 'a', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><polygon points="12,18 22,18 27,28 17,38 7,38 2,28" fill="#0084AD"/><polygon points="40,15 55,15 60,25 55,35 40,35 35,25" fill="#0084AD"/><polygon points="70,12 87,12 95,25 87,38 70,38 62,25" fill="#0084AD"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
('pattern_recognition', 'easy', 'What color comes next in the pattern?', 'Teal', 'Orange', 'Gray', 'White', 'b', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="15" cy="25" r="8" fill="#0084AD"/><circle cx="40" cy="25" r="8" fill="#BC3F1D"/><circle cx="65" cy="25" r="8" fill="#0084AD"/><circle cx="90" cy="25" r="8" fill="#BC3F1D"/><text x="150" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
