('spatial', 'medium', 'What unfolded net creates this 3D shape?', 'Net A', 'Net B', 'Net C', 'Net D', 'a', '<svg viewBox="0 0 200 80" xmlns="http://www.w3.org/2000/svg"><polygon points="40,20 60,20 60,40 40,40" fill="#0084AD"/><polygon points="60,20 80,20 80,40 60,40" fill="#0084AD"/><polygon points="80,20 100,20 100,40 80,40" fill="#0084AD"/><polygon points="60,40 80,40 80,60 60,60" fill="#0084AD"/><polygon points="60,0 80,0 80,20 60,20" fill="#0084AD"/><polygon points="40,40 60,40 60,60 40,60" fill="#0084AD"/></svg>', false, true),
('spatial', 'medium', 'Which shape is a 90° rotation in 3D space?', 'Shape A', 'Shape B', 'Shape C', 'Shape D', 'b', '<svg viewBox="0 0 200 60" xmlns="http://www.w3.org/2000/svg"><polygon points="25,15 45,10 50,35 30,40" fill="#0084AD"/><polygon points="80,30 90,15 105,20 95,35" fill="white" stroke="#0084AD" stroke-width="2"/><polygon points="135,30 155,35 150,55 130,50" fill="#0084AD"/></svg>', false, true),
('spatial', 'medium', 'How many cubes are in this 3D structure?', '4', '6', '8', '10', 'c', '<svg viewBox="0 0 200 70" xmlns="http://www.w3.org/2000/svg"><polygon points="30,30 50,25 50,45 30,50" fill="#0084AD"/><polygon points="50,25 70,20 70,40 50,45" fill="#0084AD" opacity="0.8"/><polygon points="30,50 50,45 50,65 30,70" fill="#0084AD" opacity="0.6"/><polygon points="70,40 90,35 90,55 70,60" fill="#0084AD"/><polygon points="90,35 110,30 110,50 90,55" fill="#0084AD" opacity="0.8"/><polygon points="70,60 90,55 90,75 70,80" fill="#0084AD" opacity="0.6"/></svg>', false, true),
('spatial', 'medium', 'Which cross-section matches the 3D object?', 'Section A', 'Section B', 'Section C', 'Section D', 'c', '<svg viewBox="0 0 200 60" xmlns="http://www.w3.org/2000/svg"><polygon points="35,15 55,15 60,40 40,40" fill="#0084AD"/><polygon points="65,15 85,15 90,40 70,40" fill="#0084AD"/><polygon points="100,20 115,20 120,35 105,35" fill="white" stroke="#0084AD" stroke-width="2"/><polygon points="140,15 160,15 165,40 145,40" fill="#0084AD"/></svg>', false, true),
('spatial', 'medium', 'What is the correct folding pattern?', 'Fold A', 'Fold B', 'Fold C', 'Fold D', 'd', '<svg viewBox="0 0 200 60" xmlns="http://www.w3.org/2000/svg"><line x1="50" y1="20" x2="50" y2="40" stroke="#999" stroke-width="1" stroke-dasharray="2,2"/><polygon points="20,20 50,20 50,40 20,40" fill="#0084AD"/><polygon points="50,20 80,20 80,40 50,40" fill="#0084AD" opacity="0.7"/><text x="15" y="55" font-size="11" fill="#4A6572">Fold line</text></svg>', false, true),
('spatial', 'medium', 'Which represents the bottom view?', 'View A', 'View B', 'View C', 'View D', 'a', '<svg viewBox="0 0 200 60" xmlns="http://www.w3.org/2000/svg"><polygon points="40,15 70,10 75,35 45,40" fill="#0084AD"/><text x="20" y="55" font-size="11" fill="#4A6572">3D object</text><polygon points="120,20 150,20 150,35 120,35" fill="white" stroke="#0084AD" stroke-width="2"/><text x="100" y="55" font-size="11" fill="#4A6572">Bottom view</text></svg>', false, true),
('spatial', 'medium', 'How does the shape transform?', 'Expand', 'Rotate', 'Compress', 'Reflect', 'b', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><polygon points="20,18 30,18 25,32" fill="#0084AD"/><polygon points="45,22 45,28 55,25" fill="#0084AD"/><polygon points="70,32 70,18 80,25" fill="#0084AD"/><text x="155" y="30" font-size="12" fill="#4A6572">?</text></svg>', false, true),
