('spatial', 'medium', 'What is the correct spatial arrangement?', 'A before B', 'B before A', 'A left of B', 'B left of A', 'c', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="30" cy="25" r="8" fill="#0084AD"/><rect x="75" y="17" width="16" height="16" fill="#0084AD"/><text x="20" y="40" font-size="10" fill="#4A6572">A</text><text x="80" y="40" font-size="10" fill="#4A6572">B</text></svg>', false, true),
