('spatial', 'medium', 'What is the depth perception match?', 'Shallow', 'Medium', 'Deep', 'Very deep', 'a', '<svg viewBox="0 0 200 50" xmlns="http://www.w3.org/2000/svg"><circle cx="20" cy="25" r="5" fill="#0084AD"/><circle cx="45" cy="25" r="8" fill="#0084AD" opacity="0.7"/><circle cx="70" cy="25" r="12" fill="#0084AD" opacity="0.5"/></svg>', false, true);
